const fadeIn = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.5 } }
};

// ─── Section wrapper ────────────────────────────────────────
const Section = ({ children, style, id }) => (
    <motion.section
        id={id}
        variants={fadeIn}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: '-40px' }}
        style={{
            background: '#FFFFFF',
            borderRadius: '20px',
            border: '1px solid #E2E8F0',
            padding: '36px 32px',
            marginBottom: '28px',
            scrollMarginTop: '100px',
            ...style,
        }}
    >
        {children}
    </motion.section>
);

